import{_ as e,o,c as a,ai as s}from"./chunks/framework.DMjte4z8.js";const u=JSON.parse('{"title":"JASS 脚本基础入门","description":"","frontmatter":{"title":"JASS 脚本基础入门","category":"scripting","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/forums/scripting-tutorials.280/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=34165","http://www.wc3c.net/tutorials.php?f=650","https://wc3we.fandom.com/wiki/Jass_Coding","https://jass.sourceforge.net/doc/","https://warcraft.wiki.gg/wiki/JASS","https://wowpedia.fandom.com/wiki/JASS"]},"headers":[],"relativePath":"scripting/jass-脚本基础入门.md","filePath":"scripting/jass-脚本基础入门.md","lastUpdated":1778216780000}'),n={name:"scripting/jass-脚本基础入门.md"};function r(i,t,l,d,c,p){return o(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="jass-脚本基础入门" tabindex="-1">JASS 脚本基础入门 <a class="header-anchor" href="#jass-脚本基础入门" aria-label="Permalink to “JASS 脚本基础入门”">​</a></h1><h2 id="jass简介与学习准备" tabindex="-1">JASS简介与学习准备 <a class="header-anchor" href="#jass简介与学习准备" aria-label="Permalink to “JASS简介与学习准备”">​</a></h2><p>本节将带你认识JASS脚本语言，了解为什么学习它对你的地图创作有帮助，并学会如何打开JASS编辑环境。完成本节后，你将能够顺利进入JASS代码编写界面，为后续学习打下基础。</p><h3 id="什么是jass脚本" tabindex="-1">什么是JASS脚本 <a class="header-anchor" href="#什么是jass脚本" aria-label="Permalink to “什么是JASS脚本”">​</a></h3><p>JASS是&quot;Just Another Scripting Syntax&quot;的缩写，中文可以理解为&quot;另一种脚本语法&quot;[^7]。它是一种专门为《魔兽争霸3》设计的编程语言，用于控制游戏中的各种行为，比如单位的移动、攻击、创建，以及游戏逻辑的判断和执行[^6]。</p><blockquote><p><strong>💡 新手提示</strong>：把JASS想象成一本&quot;游戏控制说明书&quot;。你用JASS写下指令，告诉电脑在什么情况下该做什么事情。比如&quot;当英雄死亡时，播放音效并显示文字&quot;这样的规则。</p></blockquote><h3 id="为什么学习jass" tabindex="-1">为什么学习JASS <a class="header-anchor" href="#为什么学习jass" aria-label="Permalink to “为什么学习JASS”">​</a></h3><p>在《魔兽争霸3》中，你可能已经用过&quot;触发器编辑器&quot;（Trigger Editor）来创建游戏规则。触发器编辑器提供了可视化界面，让你可以通过点击和选择来创建规则。但实际上，<strong>每一你在触发器编辑器中创建的操作，背后都会自动生成对应的JASS代码</strong>[^4]。</p><p>学习JASS有以下几个重要理由：</p><ol><li><strong>更精确的控制</strong> — 有些游戏功能只能在JASS中实现，可视化界面无法完成[^1]</li><li><strong>理解底层原理</strong> — 知道代码在做什么，能帮你更好地调试和优化地图</li><li><strong>阅读和修改</strong> — 你可以查看暴雪自带触发器生成的代码，学习高级技巧</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手觉得&quot;我不用学代码，用可视化界面就够了&quot;。但当你遇到复杂需求时，比如自定义技能系统或特殊游戏机制，就会发现JASS知识是必须掌握的核心技能。</p></blockquote><h3 id="打开jass编辑环境" tabindex="-1">打开JASS编辑环境 <a class="header-anchor" href="#打开jass编辑环境" aria-label="Permalink to “打开JASS编辑环境”">​</a></h3><p>JASS编辑器并不是一个独立的程序，它<strong>集成在世界编辑器（World Editor）内部的触发器编辑器中</strong>。下面我们一步步来打开它：</p><ol><li><p><strong>第一步：启动世界编辑器</strong> — 找到并打开《魔兽争霸3》的安装目录，双击&quot;World Editor.exe&quot;。如果桌面上有快捷方式，也可以直接双击打开[^2]</p></li><li><p><strong>第二步：打开触发器编辑器</strong> — 在世界编辑器主界面，找到顶部菜单栏中的&quot;触发器&quot;按钮（图标像一个闪电符号），点击它即可打开触发器编辑器窗口</p></li><li><p><strong>第三步：进入JASS代码编辑模式</strong> — 在触发器编辑器中，选择菜单 <strong>编辑 → 新建自定义脚本</strong>，或者直接按快捷键 <strong>Ctrl + U</strong>。这将创建一个新的空白JASS脚本文件</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：首次打开触发器编辑器时，会看到一些系统自带的预设触发器（如&quot;Map Initialization&quot;）。你可以双击打开它们查看生成的JASS代码，这是学习JASS的好方法！</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经：</p><ul><li>理解了JASS是什么（游戏脚本语言）</li><li>明白了学习JASS的价值（更强大的地图控制能力）</li><li>能够打开JASS编辑环境，进入触发器编辑器并创建自定义脚本</li></ul><p>接下来，我们将开始学习JASS的基础语法和常用命令。准备好了吗？</p><h2 id="jass基本语法结构" tabindex="-1">JASS基本语法结构 <a class="header-anchor" href="#jass基本语法结构" aria-label="Permalink to “JASS基本语法结构”">​</a></h2><p>本节将带你认识JASS代码的&quot;外貌&quot;——了解代码长什么样、怎么写注释、以及最容易出错的书写规范。学完之后，你就能够读懂最简单的JASS代码片段了。</p><h3 id="代码基本结构" tabindex="-1">代码基本结构 <a class="header-anchor" href="#代码基本结构" aria-label="Permalink to “代码基本结构”">​</a></h3><p>JASS代码看起来复杂，但它的基本结构其实很有规律，就像搭积木一样。每一块积木（叫做&quot;函数&quot;）负责完成一个具体任务。</p><ol><li><strong>首先，打开触发器编辑器</strong> — 在World Editor顶部菜单栏点击&quot;触发器&quot;按钮[^1]</li><li><strong>创建一个新的触发器</strong> — 右键触发器列表，选择&quot;新建触发器&quot;，双击打开编辑界面</li><li><strong>点击&quot;编辑&quot;菜单</strong> — 在触发器编辑界面找到并点击&quot;编辑&quot;→&quot;转换为JASS&quot;[^2]</li><li><strong>观察代码窗口</strong> — 你会看到类似这样的结构：</li></ol><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function MyFunction takes nothing returns nothing</span></span>
<span class="line"><span>    // 这里是函数的代码</span></span>
<span class="line"><span>endfunction</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>每一段JASS代码都以 <code>function</code> 开头，以 <code>endfunction</code> 结束，中间的 <code>takes</code> 后面写这个函数需要什么参数，<code>returns</code> 后面写它会输出什么结果。</p><blockquote><p><strong>💡 新手提示</strong>：记住 <code>function</code> 和 <code>endfunction</code> 必须成对出现！漏掉任何一个都会报错。建议写代码时先把这对单词写好，再往中间填内容。</p></blockquote><h3 id="注释的使用方法" tabindex="-1">注释的使用方法 <a class="header-anchor" href="#注释的使用方法" aria-label="Permalink to “注释的使用方法”">​</a></h3><p>注释就像是代码的&quot;小抄&quot;——你可以在代码旁边写中文说明，让自己以后阅读时能快速想起这段代码是做什么的。计算机不会执行注释内容，所以你可以放心写中文[^4]。</p><ol><li><strong>单行注释</strong> — 在代码前面加 <code>//</code>，这行后面的内容就会变成灰色，不会被程序执行</li></ol><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function Trig_Example_Actions takes nothing returns nothing</span></span>
<span class="line"><span>    // 这是一个注释，计算不会管它</span></span>
<span class="line"><span>    call DisplayTextToForce(GetPlayersAll(), &quot;你好&quot;) // 这里的注释在代码后面</span></span>
<span class="line"><span>endfunction</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ol start="2"><li><strong>多行注释</strong> — 用 <code>/*</code> 开始，用 <code>*/</code> 结束，中间可以跨多行</li></ol><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/*</span></span>
<span class="line"><span>这段注释可以写很多很多行</span></span>
<span class="line"><span>非常适合写详细的说明</span></span>
<span class="line"><span>比如解释整个触发器的功能</span></span>
<span class="line"><span>*/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把注释符号写反，比如写成 <code>//*/</code>。正确的单行注释只有一个 <code>//</code>，正确的多行注释是 <code>/*</code> 开头、<code>*/</code> 结尾。</p></blockquote><h3 id="大小写与空格规范" tabindex="-1">大小写与空格规范 <a class="header-anchor" href="#大小写与空格规范" aria-label="Permalink to “大小写与空格规范”">​</a></h3><p>JASS对大小写<strong>非常敏感</strong>！这是个很容易踩的坑。<code>DisplayTextToForce</code> 和 <code>displaytexttoforce</code> 在JASS眼里是完全不同的两个东西[^5]。</p><ol><li><strong>严格区分大小写</strong> — JASS中所有函数名、关键字、变量名都必须使用<strong>正确的大小写</strong>[^6]</li><li><strong>推荐习惯</strong> — 函数名通常首字母大写，其他单词首字母也大写（如 <code>GetTriggerUnit</code>、<code>CreateUnitAtLoc</code>）</li><li><strong>空格的使用</strong> — 关键字之间、参数之间需要用空格隔开，但不要在单词中间加空格</li></ol><blockquote><p><strong>💡 新手提示</strong>：最好的学习方法是在World Editor中直接复制粘贴官方示例代码，而不是自己手动输入。手动输入容易出错，而复制来的代码大小写一定是正确的。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该：</p><ul><li>能认出JASS代码的 <code>function...endfunction</code> 基本框架</li><li>能在代码中写单行注释 <code>//</code> 和多行注释 <code>/* */</code></li><li>记住JASS<strong>区分大小写</strong>，函数名不能写错</li><li>下一步可以学习如何用JASS写一个简单的触发器逻辑了！</li></ul><h2 id="变量与数据类型" tabindex="-1">变量与数据类型 <a class="header-anchor" href="#变量与数据类型" aria-label="Permalink to “变量与数据类型”">​</a></h2><p>本节将带你认识 JASS 脚本中最基础也最重要的概念——<strong>变量</strong>与<strong>数据类型</strong>。学完本节后，你将能够创建自己的变量，并在脚本中正确使用不同类型的数据。</p><h3 id="声明变量" tabindex="-1">声明变量 <a class="header-anchor" href="#声明变量" aria-label="Permalink to “声明变量”">​</a></h3><p>在 JASS 中，声明变量就像给一个&quot;盒子&quot;贴上标签一样，你需要给这个盒子起个名字，并告诉计算机里面要装什么类型的东西。</p><p><strong>操作步骤：</strong></p><ol><li><p><strong>理解变量声明的语法</strong> — 在 JASS 中，我们使用 <code>set</code> 关键字来声明变量[^1]。语法格式是：<code>set 变量名 = 值</code>[^4]</p></li><li><p><strong>创建第一个变量</strong> — 例如，如果你想创建一个叫 <code>hp</code> 的整数变量，可以这样写：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>set udg_hp = 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 <code>udg_</code> 前缀表示这是一个<strong>全局变量</strong>（后面会详细讲解）</p></li><li><p><strong>注意变量名的命名规则</strong> — 变量名必须以字母开头，可以包含数字和下划线，不能使用空格或中文[^5]</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记在变量名加 <code>udg_</code> 前缀，导致变量无法被触发器识别。一定要记住，全局变量必须加 <code>udg_</code> 前缀！</p></blockquote><h3 id="常见数据类型" tabindex="-1">常见数据类型 <a class="header-anchor" href="#常见数据类型" aria-label="Permalink to “常见数据类型”">​</a></h3><p>数据类型决定了变量可以存放什么种类的信息。就像不同的盒子适合装不同的东西一样，不同的数据类型也有各自的用途[^6]。</p><p><strong>常见数据类型一览：</strong></p><table tabindex="0"><thead><tr><th>数据类型</th><th>中文名</th><th>用途</th><th>示例</th></tr></thead><tbody><tr><td><code>integer</code></td><td>整数</td><td>存放整数（如 1、100、-5）</td><td><code>set udg_score = 999</code></td></tr><tr><td><code>real</code></td><td>实数</td><td>存放小数（如 3.14、0.5）</td><td><code>set udg_damage = 50.5</code></td></tr><tr><td><code>string</code></td><td>字符串</td><td>存放文字</td><td><code>set udg_name = &quot;Hero&quot;</code></td></tr><tr><td><code>boolean</code></td><td>布尔值</td><td>存放真假（true/false）</td><td><code>set udg_isAlive = true</code></td></tr><tr><td><code>unit</code></td><td>单位</td><td>存放游戏中的单位</td><td><code>set udg_hero = gg_unit_H000_0001</code></td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：在 WE 的变量编辑器中创建变量时，系统会要求你选择数据类型。选错类型会导致脚本运行错误，所以创建前要先想清楚这个变量要存什么！</p></blockquote><h3 id="全局变量与局部变量" tabindex="-1">全局变量与局部变量 <a class="header-anchor" href="#全局变量与局部变量" aria-label="Permalink to “全局变量与局部变量”">​</a></h3><p>理解<strong>全局变量</strong>和<strong>局部变量</strong>的区别，是写出正确脚本的关键一步[^2]。</p><p><strong>全局变量：</strong></p><ul><li>在地图加载时就存在，整个脚本运行期间都可以使用</li><li>在变量编辑器中创建的变量都是全局变量</li><li>使用时需要在名字前加 <code>udg_</code> 前缀（意为 &quot;User-Derined Global&quot;）[^5]</li></ul><p><strong>局部变量：</strong></p><ul><li>在函数内部声明，只在该函数执行时存在</li><li>使用 <code>local</code> 关键字声明，例如：<code>local integer count = 0</code>[^4]</li><li>函数执行完毕后，局部变量会被自动销毁</li></ul><p><strong>何时使用哪种？</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>推荐使用</th></tr></thead><tbody><tr><td>需要在多个触发器间共享数据</td><td>全局变量</td></tr><tr><td>只在一个函数内部临时使用</td><td>局部变量</td></tr><tr><td>需要保存玩家的选择或进度</td><td>全局变量</td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：作为新手，建议先只使用全局变量。虽然局部变量效率更高，但对于 KK 平台的基础地图来说，全局变量已经完全够用，而且更容易管理！</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上学习后，你应该已经掌握了：</p><ul><li>✅ 如何使用 <code>set udg_变量名 = 值</code> 的格式声明全局变量</li><li>✅ 认识了 integer、real、string、boolean、unit 等常用数据类型</li><li>✅ 理解了全局变量与局部变量的区别</li></ul><p><strong>动手试试看：</strong></p><ol><li>打开 WE 的变量编辑器（触发器编辑器上方有一个📦图标）</li><li>创建一个名为 <code>PlayerGold</code> 的整数变量</li><li>在触发器中使用 <code>set udg_PlayerGold = 500</code> 给玩家初始500金币</li></ol><p>这样，你就完成了第一个属于自己的变量操作！</p><h2 id="函数基础" tabindex="-1">函数基础 <a class="header-anchor" href="#函数基础" aria-label="Permalink to “函数基础”">​</a></h2><p>本节我们将学习JASS中的&quot;函数&quot;概念。函数就像是厨房里的&quot;菜谱&quot;——你可以提前写好制作步骤（定义函数），然后每次需要时调用这个菜谱来执行。掌握函数后，你的脚本会更简洁、更易维护。</p><h3 id="如何定义函数" tabindex="-1">如何定义函数 <a class="header-anchor" href="#如何定义函数" aria-label="Permalink to “如何定义函数”">​</a></h3><p>在JASS中，定义一个函数需要使用 <code>function</code> 关键字[^5]。</p><p><strong>操作步骤：</strong></p><ol><li><strong>打开触发编辑器</strong> — 在World Editor中按 <code>F4</code> 打开触发编辑器[^1]</li><li><strong>切换到自定义脚本</strong> — 右键点击触发器，选择&quot;编辑&quot; → &quot;自定义脚本&quot;，这允许你直接输入JASS代码[^2]</li><li><strong>输入函数定义</strong> — 按照以下格式书写：<div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function MyFunction takes nothing returns nothing</span></span>
<span class="line"><span>    // 在这里写你的代码</span></span>
<span class="line"><span>endfunction</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><strong>解释语法</strong>： <ul><li><code>function</code> — 告诉电脑&quot;我要定义一个新函数&quot;</li><li><code>MyFunction</code> — 函数的名字（可以自己起，但要用英文和数字）</li><li><code>takes nothing</code> — 函数不需要任何&quot;材料&quot;（参数）</li><li><code>returns nothing</code> — 函数执行完不返回任何结果</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记写 <code>endfunction</code>，导致代码报错。每个 <code>function</code> 必须有一个对应的 <code>endfunction</code>，就像每句话要有句号一样。</p></blockquote><h3 id="调用函数" tabindex="-1">调用函数 <a class="header-anchor" href="#调用函数" aria-label="Permalink to “调用函数”">​</a></h3><p>定义好函数后，你可以在任何地方&quot;调用&quot;它——也就是让函数执行它的代码[^6]。</p><p><strong>操作步骤：</strong></p><ol><li><strong>在触发器中调用</strong> — 在触发器的&quot;动作&quot;中找到&quot;自定义脚本&quot;选项[^1]</li><li><strong>输入调用语句</strong> — 只需写函数名加括号：<div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call MyFunction()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><strong>理解 <code>call</code> 的作用</strong> — <code>call</code> 是&quot;调用&quot;的意思，它告诉电脑：&quot;去执行名为MyFunction的函数&quot;</li></ol><blockquote><p><strong>💡 新手提示</strong>：调用函数时，函数必须是在你调用之前已经定义好的。就像你要做菜，得先把菜谱写好，才能按菜谱做菜。</p></blockquote><h3 id="常用原生函数" tabindex="-1">常用原生函数 <a class="header-anchor" href="#常用原生函数" aria-label="Permalink to “常用原生函数”">​</a></h3><p>原生函数是World Editor提前为你准备好的&quot;工具函数&quot;[^4]，你不需要定义它们，直接调用即可。</p><p><strong>最常用的几个：</strong></p><table tabindex="0"><thead><tr><th>函数名</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><code>BJDebugMsg(&quot;消息&quot;)</code></td><td>在屏幕上方显示调试信息</td><td><code>call BJDebugMsg(&quot;Hello World&quot;)</code></td></tr><tr><td><code>GetTriggerUnit()</code></td><td>获取触发事件的单位</td><td>常用于单位类触发器</td></tr><tr><td><code>GetOwningPlayer(unit)</code></td><td>获取单位所属玩家</td><td><code>GetOwningPlayer(GetTriggerUnit())</code></td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：函数名后面跟的括号里的内容叫做&quot;参数&quot;，不同函数需要不同的参数。鼠标悬停在函数上可以看到它需要什么参数。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成本节学习后，你应该：</p><ul><li>✅ 能用 <code>function...takes...returns...endfunction</code> 的格式定义一个简单函数</li><li>✅ 能在触发器中使用 <code>call 函数名()</code> 来调用你定义的函数</li><li>✅ 能使用 <code>BJDebugMsg()</code> 在游戏中显示信息来测试你的代码</li></ul><p>下一步，你可以尝试写一个简单的函数，让它显示&quot;我的第一个函数！&quot;的消息。</p><h2 id="触发器与jass的结合" tabindex="-1">触发器与JASS的结合 <a class="header-anchor" href="#触发器与jass的结合" aria-label="Permalink to “触发器与JASS的结合”">​</a></h2><p>本节将教你如何把GUI触发器（图形界面触发器）转换为JASS代码，并帮助你理解在什么情况下应该选择使用JASS而不是纯GUI触发器。完成学习后，你将能够自由切换两种模式，并根据实际需求做出选择。</p><h3 id="触发器转jass方法" tabindex="-1">触发器转JASS方法 <a class="header-anchor" href="#触发器转jass方法" aria-label="Permalink to “触发器转JASS方法”">​</a></h3><ol><li><p><strong>打开触发器编辑器</strong> — 在World Editor中，点击顶部菜单的&quot;触发器编辑器&quot;按钮（也称为Trigger Editor），进入触发器管理界面[^2]。</p></li><li><p><strong>选择你要转换的触发器</strong> — 在左侧触发器列表中，找到你想要查看JASS代码的触发器，用鼠标单击选中它。</p></li><li><p><strong>切换到JASS视图</strong> — 选中触发器后，点击菜单栏的&quot;编辑&quot;→&quot;转换为JASS&quot;，或者直接按快捷键 <code>Ctrl + Alt + C</code>[^4]。World Editor会将该触发器的所有条件（Conditions）和动作（Actions）转换为对应的JASS代码。</p></li><li><p><strong>查看并编辑JASS代码</strong> — 转换后，代码会显示在右侧的代码编辑区域。你可以直接在这里修改代码、添加注释，或者复制代码到其他位置使用。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：转换后的JASS代码通常包含很多 <code>BJ</code> 开头的函数（如 <code>GetTriggerUnit</code> 对应 <code>GetBJ...</code>），这些是暴雪提供的&quot;便利函数&quot;，初学者可以直接使用它们，不需要完全理解底层原理。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手转换后发现代码看不懂，就直接删除整个触发器重新来过。正确的做法是先仔细对比GUI触发器的设置和JASS代码的对应关系——每一行条件/动作都有对应的代码行，理解对应关系才是学习JASS的正确起点。</p></blockquote><h3 id="何时使用jass" tabindex="-1">何时使用JASS <a class="header-anchor" href="#何时使用jass" aria-label="Permalink to “何时使用JASS”">​</a></h3><p><strong>建议使用JASS的场景：</strong></p><ol><li><p><strong>需要创建自定义函数</strong> — 当你在多个触发器中重复使用相同的逻辑时，可以将这些逻辑写成JASS自定义函数，避免代码冗余[^1]。</p></li><li><p><strong>需要更精细的事件响应</strong> — JASS支持更多类型的事件（Event），比如单位属性变化、游戏时间精确控制等[^6]。</p></li><li><p><strong>性能敏感的操作</strong> — 对于需要大量循环计算或实时检测的任务，直接用JASS编写往往比GUI触发器更高效。</p></li><li><p><strong>使用第三方JASS库</strong> — 许多社区提供的脚本库（如TESH高亮支持库、自定义伤害系统）需要以JASS形式加载[^1]。</p></li></ol><p><strong>仍建议使用GUI触发器的场景：</strong></p><ul><li>地图逻辑相对简单，没有复杂的循环或数学计算</li><li>你还不熟悉JASS语法，不想在调试上花费过多时间</li><li>需要快速原型验证创意的阶段</li></ul><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经掌握了将GUI触发器转换为JASS的基本操作，并了解了两种方式各自的适用场景。建议你先从简单的触发器开始尝试转换，观察JASS代码的组织结构，等熟悉后再逐步尝试编写纯JASS代码。记住，<strong>工具的选择永远服务于你的创作需求</strong>——不要为了&quot;用JASS而用JASS&quot;，而要为了解决实际问题去学习它。</p><h2 id="实用技巧与常见错误" tabindex="-1">实用技巧与常见错误 <a class="header-anchor" href="#实用技巧与常见错误" aria-label="Permalink to “实用技巧与常见错误”">​</a></h2><p>本节会介绍编写JASS脚本时新手最常犯的错误，以及让代码更简洁、更高效的实用技巧。学完本节后，你将能够识别并避免常见陷阱，写出更专业的脚本。</p><h3 id="常见错误与解决方法" tabindex="-1">常见错误与解决方法 <a class="header-anchor" href="#常见错误与解决方法" aria-label="Permalink to “常见错误与解决方法”">​</a></h3><ol><li><p><strong>大小写敏感问题</strong> — JASS是一种对大小写敏感的语言，&quot;SetUnitX&quot;和&quot;setunitx&quot;在JASS眼中是完全不同的东西[^1]。如果编辑器提示&quot;找不到函数&quot;，首先检查大小写是否完全正确。</p></li><li><p><strong>缺少分号或引号</strong> — 每条JASS语句必须以分号（;）结尾，字符串内容必须用双引号包围。比如 <code>call DisplayTextToPlayer(p, 0, 0, &quot;你好&quot;)</code> ，忘记任何一个符号都会报错。</p></li><li><p><strong>GUI变量名与JASS变量名混淆</strong> — 在触发器编辑器里创建的变量，JASS里使用的是完全不同的名字。如果提示&quot;找不到变量&quot;，检查是否在脚本顶部正确声明了变量。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：复制别人代码后报&quot;函数已存在&quot;错误。解决方法很简单——给函数起一个唯一的名字，或者在脚本开头加一行 <code>function main takes nothing returns nothing</code> 检查是否已有同名函数[^3]。</p></blockquote><h3 id="jass代码优化建议" tabindex="-1">JASS代码优化建议 <a class="header-anchor" href="#jass代码优化建议" aria-label="Permalink to “JASS代码优化建议”">​</a></h3><ol><li><p><strong>多用局部变量</strong> — 在函数内部用 <code>local</code> 关键字声明的变量比全局变量运行速度更快。比如 <code>local unit u = GetTriggerUnit()</code> ，用完就自动释放。</p></li><li><p><strong>避免频繁创建和销毁单位</strong> — 创建一个单位需要消耗大量计算机资源（就像真的在地图上生成一个角色）。建议尽量复用已有的单位，而不是反复创建再删除。</p></li><li><p><strong>学会使用vJASS</strong> — vJASS是JASS的&quot;升级版&quot;，支持库、模块、结构体等高级功能[^4]。学会它之后，你会发现写复杂系统变得轻松很多。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：写完代码后养成用 <code>//</code> 添加注释的习惯。比如 <code>// 这是获取触发单位的代码</code>，这样以后回头看自己能快速理解。注释不会影响程序运行，但能让代码维护变得简单。</p></blockquote><h3 id="学习资源推荐" tabindex="-1">学习资源推荐 <a class="header-anchor" href="#学习资源推荐" aria-label="Permalink to “学习资源推荐”">​</a></h3><ul><li><strong>Hiveworkshop</strong> — 最大的魔兽争霸脚本社区，包含大量JASS和vJASS教程[^1]</li><li><strong>TheHelper &quot;So You Want to Learn JASS?&quot;</strong> — 专门为零基础新手设计的入门指南[^2]</li><li><strong>JASS Manual</strong> — 官方语言参考手册，适合当&quot;字典&quot;随时查阅[^5]</li></ul><blockquote><p><strong>💡 新手提示</strong>：不要试图一口气学完所有内容。建议每次只研究一个功能模块，比如&quot;如何让单位移动&quot;，学会后就动手做一个小练习，这样学习效率最高。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该能够识别JASS中最常见的几种错误类型（大小写、分号、引号、变量名），掌握三条让代码更高效的基本原则，并知道去哪里继续深入学习。记住：写代码不怕出错，怕的是同一个错误犯两次——每次遇到报错都是学习的好机会！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/forums/scripting-tutorials.280/" target="_blank" rel="noreferrer">Warcraft 3 Scripting Tutorials (JASS, Lua, vJASS, TypeScript, AI, etc.)</a> — accessed 2026-05-08 [^2]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=34165" target="_blank" rel="noreferrer">So You Want to Learn JASS? - World Editor tutorials</a> — accessed 2026-05-08 [^3]: <a href="http://www.wc3c.net/tutorials.php?f=650" target="_blank" rel="noreferrer">JASS/AI scripts tutorials - WC3Campaigns</a> — accessed 2026-05-08 [^4]: <a href="https://wc3we.fandom.com/wiki/Jass_Coding" target="_blank" rel="noreferrer">Jass Coding | Warcraft 3 World Editor Wiki | Fandom</a> — accessed 2026-05-08 [^5]: <a href="https://jass.sourceforge.net/doc/" target="_blank" rel="noreferrer">JASS Manual</a> — accessed 2026-05-08 [^6]: <a href="https://warcraft.wiki.gg/wiki/JASS" target="_blank" rel="noreferrer">JASS - Warcraft Wiki</a> — accessed 2026-05-08 [^7]: <a href="https://wowpedia.fandom.com/wiki/JASS" target="_blank" rel="noreferrer">JASS - Wowpedia</a> — accessed 2026-05-08</p>`,117)])])}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
